try {
  const llm = await this.getInputConnectionData('ai_languageModel', 0);
  const toolsArray = (await this.getInputConnectionData('ai_tool', 0)) || [];
  if (!llm || toolsArray.length === 0) throw new Error('LLM или инструменты не подключены');

  // 2. ДИНАМИЧЕСКИЙ СПРАВОЧНИК ДАТ
  const now = new Date();
  const fmt = (d) => d.toISOString().split('T')[0];
  const fmtRu = (d) => {
    const months = ['января', 'февраля', 'марта', 'апреля', 'мая', 'июня', 'июля', 'августа', 'сентября', 'октября', 'ноября', 'декабря'];
    return `${d.getDate()} ${months[d.getMonth()]} ${d.getFullYear()}`;
  };

  const getRelativeDate = (days) => {
    const d = new Date(now);
    d.setDate(now.getDate() + days);
    return d;
  };

  // Вычисляем границы недель
  const day = now.getDay();
  const monday = new Date(now);
  monday.setDate(now.getDate() + (day === 0 ? -6 : 1 - day));
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);

  const nextMonday = new Date(monday);
  nextMonday.setDate(monday.getDate() + 7);
  const nextSunday = new Date(nextMonday);
  nextSunday.setDate(nextMonday.getDate() + 6);

  // Поиск следующего четверга
  const nextThursday = new Date(now);
  nextThursday.setDate(now.getDate() + ((4 + 7 - now.getDay()) % 7 || 7));

  const periods = {
    today: { s: `${fmt(now)}T00:00:00`, e: `${fmt(now)}T23:59:59` },
    tomorrow: { s: `${fmt(getRelativeDate(1))}T00:00:00`, e: `${fmt(getRelativeDate(1))}T23:59:59` },
    thisWeek: { s: `${fmt(monday)}T00:00:00`, e: `${fmt(sunday)}T23:59:59` },
    nextWeek: { s: `${fmt(nextMonday)}T00:00:00`, e: `${fmt(nextSunday)}T23:59:59` },
    nextThu: { s: `${fmt(nextThursday)}T00:00:00`, e: `${fmt(nextThursday)}T23:59:59` }
  };

  // 3. СИСТЕМНЫЙ ПРОМПТ (Строгий формат)
  const systemPrompt = `Ты - агент Google Calendar. 
Текущее время: ${now.toISOString()} (${fmtRu(now)})
Таймзона: ${timezone}

СПРАВОЧНИК ДАТ (ИСПОЛЬЗУЙ ЭТИ ЗНАЧЕНИЯ):
- Сегодня: ${fmtRu(now)} (After: ${periods.today.s}, Before: ${periods.today.e})
- Завтра: ${fmtRu(getRelativeDate(1))} (After: ${periods.tomorrow.s}, Before: ${periods.tomorrow.e})
- Эта неделя: ${fmtRu(monday)} - ${fmtRu(sunday)} (After: ${periods.thisWeek.s}, Before: ${periods.thisWeek.e})
- Следующая неделя: ${fmtRu(nextMonday)} - ${fmtRu(nextSunday)} (After: ${periods.nextWeek.s}, Before: ${periods.nextWeek.e})
- Следующий четверг: ${fmtRu(nextThursday)} (After: ${periods.nextThu.s}, Before: ${periods.nextThu.e})

ПРАВИЛА ОТВЕТА (ОБЯЗАТЕЛЬНО):
1. getEvents (список): "Список задач на неделю: [дата] – [дата]\\n- [дата], [время], [название]"
2. getEvents (одна задача): "Задача на [дата], «[название]»:\\n- Время: [время]\\n- Дополнительно: [описание]\\n- Уведомления: стандартные напоминания\\n- ID: [id]"
3. createEvents: "Задача «[название]», [дата], [время] создана. Дополнительно: [описание]"
4. deleteEvents: "Задача «[название]», [дата] в [время] удалена" (или "Все задачи за [период] удалены")
5. updateEvents: "Задача «[название]», [дата], [время] обновлена. Добавлено: [что добавлено]"

ПРАВИЛА РАБОТЫ:
- Всегда используй ISO 8601 с таймзоной для инструментов.
- Если время не указано, ставь 12:00 или +1 час.
- Для удаления/обновления сначала найди ID через getEvents.

ЗАПРОС: {input}`;

  const prompt = ChatPromptTemplate.fromMessages([
    ["system", systemPrompt],
    ["placeholder", "{agent_scratchpad}"]
  ]);

  const agent = await createToolCallingAgent({ llm, tools: toolsArray, prompt });
  const executor = new AgentExecutor({ agent, tools: toolsArray, maxIterations: 10, returnIntermediateSteps: true });

  const result = await executor.invoke({ input: query });
  agentOutput = result.output;

  // 4. СБОР ДАННЫХ ДЛЯ ВЫХОДА
  if (result.intermediateSteps?.length > 0) {
    const lastStep = result.intermediateSteps[result.intermediateSteps.length - 1];
    action = lastStep.action.tool;
    const tIn = lastStep.action.toolInput;
    eventName = tIn.Summary || tIn.summary || tIn.Summary_Update;
    if (tIn.Start || tIn.start) {
      [targetDate, timeStart] = (tIn.Start || tIn.start).split('T');
      timeStart = timeStart?.substring(0, 5);
    }
    try {
      parsedResult = typeof lastStep.observation === 'string' ? JSON.parse(lastStep.observation) : lastStep.observation;
    } catch {
      parsedResult = lastStep.observation;
    }
  }

  const rawEvents = parsedResult?.items || parsedResult?.events || (Array.isArray(parsedResult) ? parsedResult : [parsedResult]);
  events = (Array.isArray(rawEvents) ? rawEvents : []).filter(e => e && (e.id || e.summary)).map(e => ({
    ...e,
    name: e.summary || e.name || null,
    date: e.start?.dateTime?.split('T')[0] || e.start?.date || e.date || null
  }));

} catch (error) {
  executionError = error.message;
}

const actionLabels = { getEvents: 'Получение', createEvents: 'Создание', deleteEvents: 'Удаление', updateEvents: 'Обновление' };

return [{
  json: {
    success: !executionError,
    error: executionError,
    action,
    action_readable: actionLabels[action] || action,
    event_name: eventName || events[0]?.name || null,
    date: targetDate || events[0]?.date || null,
    time_start: timeStart,
    time_end: timeEnd,
    events,
    events_count: events.length,
    tool_result: parsedResult,
    original_query: query,
    confidence,
    agent_response: agentOutput
  }
}];
